<!DOCTYPE html><html lang="zh-Hant"><head><meta charset="UTF-8"><title>管理後台</title><link rel="stylesheet" href="/css/style.css"><style>.admin-wrap{max-width:800px;margin:0 auto}.form-grid{display:grid;grid-template-columns:1fr 1fr;gap:.75rem;margin-bottom:1rem}.form-grid .full{grid-column:1/-1}.form-grid input,.form-grid select,.form-grid textarea{width:100%;border:1px solid #ddd;border-radius:6px;padding:.5rem .75rem;font-size:.88rem;font-family:inherit}.card{background:#fff;border-radius:12px;border:1px solid #e8e8e8;padding:1.5rem;margin-bottom:1.5rem}.book-row{display:flex;justify-content:space-between;align-items:center;padding:.6rem 0;border-bottom:1px solid #f5f5f5}.del-btn{color:#f87171;background:none;border:none;cursor:pointer;font-size:.82rem}.del-btn:hover{color:#dc2626}.success{color:#16a34a;font-size:.88rem;margin-bottom:.75rem}</style></head><body><nav class="navbar"><div class="container nav-inner"><a href="/" class="brand">✝ 屬靈共同書目</a><div class="nav-links"><a href="/">書單</a><a href="/admin/" style="color:#fff;font-weight:700">管理後台</a></div></div></nav><main class="container py-8 admin-wrap"><h1 style="font-size:1.3rem;font-weight:700;margin-bottom:1.5rem">書目管理後台</h1><div class="card"><h2 style="font-size:1rem;margin-bottom:1rem">新增書目</h2><div id="msg"></div><div class="form-grid"><input type="text" id="fTitle" placeholder="書名 *"><input type="text" id="fAuthor" placeholder="作者 *"><input type="text" id="fTranslator" placeholder="譯者"><input type="text" id="fPublisher" placeholder="出版社"><input type="text" id="fYear" placeholder="出版年份"><input type="text" id="fIsbn" placeholder="ISBN"><select id="fCategory"><option value="">選擇分類</option><?php $cats=getDB()->query("SELECT * FROM categories ORDER BY sort_order")->fetchAll();foreach($cats as $c); ?><option value="<?= $c['slug'] ?>"><?= htmlspecialchars($c['name']) ?></option><?php endforeach; ?></select><input type="text" id="fRec" placeholder="推薦人"><input type="text" id="fCover" placeholder="封面圖片 URL" clas